#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int left=1, right=N;
        for(int i=0;i<N;i++){
            if(i%2==0){
                printf("%d", left);
                left++;
            }else{
                printf("%d", right);
                right--;
            }
            if(i+1<N) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

