    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        int l=1, r=N;
        for(int i=0;i<N;i++){
            if(i%2==0){
                cout<<l; ++l;
            }else{
                cout<<r; --r;
            }
            if(i+1<N) cout<<' ';
        }
        if(T) cout<<'\n';
    }
    return 0;
}

