import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        l, r = 1, N
        arr = []
        for i in range(N):
            if i % 2 == 0:
                arr.append(str(l))
                l += 1
            else:
                arr.append(str(r))
                r -= 1
        out_lines.append(' '.join(arr))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

